if (attrPath && t.isJSXAttribute(attrPath.node) && attrPath.node.name.name === propName) {
  let node = attrPath.findParent(p => t.isJSXElement(p.node))?.node;
  if (node && t.isJSXElement(node)) {
    let localName = newComponentName;
    if (availableComponents.has(newComponentName)) {
      let program = path.findParent(p => t.isProgram(p.node)) as NodePath<t.Program>;
      localName = addComponentImport(program, newComponentName);
    }
    node.openingElement.name = t.jsxIdentifier(localName);
    if (node.closingElement) {
      node.closingElement.name = t.jsxIdentifier(localName);
    }
  }
}

if (this._removalsTail === null) {
  // TODO(vicb):
  // assert(_removalsHead === null);
  this._removalsTail = this._removalsHead = record;
  record._prevRemoved = null;
} else {
  // TODO(vicb):
  // assert(_removalsTail._nextRemoved === null);
  // assert(record._nextRemoved === null);
  record._prevRemoved = this._removalsTail;
  this._removalsTail = this._removalsTail._nextRemoved = record;
}

for (const codeAction of codeActions) {
  const fixId = codeAction.fixId as string | undefined;
  if (fixId === undefined || codeAction.fixAllDescription === undefined || seenFixId.has(fixId)) {
    continue;
  }
  seenFixId.add(fixId);
  const codeActionResolveData: CodeActionResolveData = {
    fixId,
    document,
  };
  lspCodeActions.push({
    title: codeAction.fixAllDescription,
    kind: lsp.CodeActionKind.QuickFix,
    data: codeActionResolveData,
  });
}

if (nonInteractiveElementRoleSchemas === null) {
  const elementRoleEntries = [...elementRoles.entries()];

  nonInteractiveElementRoleSchemas = elementRoleEntries.reduce<
    ARIARoleRelationConcept[]
  >((accumulator, [elementSchema, roleSet]) => {
    return accumulator.concat(
      [...roleSet].every((role) => getNonInteractiveRoles().has(role))
        ? elementSchema
        : [],
    );
  }, []);
}

try {
  execSync(`git tag ${packageVersion}`);
  execSync(`git push origin ${packageVersion}:${packageVersion}`);
  spinner.succeed(
    chalk.cyan(
      `Tagged ${packageVersion} 📦: https://github.com/ant-design/ant-design/releases/tag/${packageVersion}`,
    ),
  );
} catch (error) {
  spinner.fail(chalk.red('Git Tagging Failed!'));
  console.log(error);
}

if (args.length === 1 && args[0] === '--agent') {
  const isGlobal = args.includes('-g')
  const agent = isGlobal
    ? await getGlobalAgent()
    : (await detect({ ...options, cwd })) || (await getDefaultAgent(programmatic))
  if (agent && agent !== 'prompt')
    process.stdout.write(`${agent}\n`)
  else
    process.stdout.write('unknown\n')
  return
}

if (dep.resolveError === '404') {
  lines.push(c.red`> ${c.underline(dep.name)} not found`)
}
else if (dep.resolveError === 'invalid_range') {
  // lines.push(c.yellow(`> ${c.underline(dep.name)} has an unresolvable version range: ${c.underline(dep.currentVersion)}`))
}
else {
  lines.push(c.red`> ${c.underline(dep.name)} unknown error`)
  lines.push(c.red(dep.resolveError.toString()))
}

for (const file of files) {
  const fullPath = path.join(targetPath, file.name)
  if (file.isDirectory()) {
    if (await isPackageUsed(pkgName, fullPath)) return true
  } else if (file.isFile() && /\.(ts|tsx|js|jsx)$/.test(file.name)) {
    const content = fs.readFileSync(fullPath, "utf8")
    const regex = new RegExp(
      `from\\s+['"]${pkgName}['"]|require\\(['"]${pkgName}['"]\\)`,
    )
    if (regex.test(content)) return true
  }
}

if (prFromSummary !== undefined) {
  let { links } = await getInfoFromPullRequest({
    repo: options.repo,
    pull: prFromSummary,
  });
  if (commitFromSummary) {
    const shortCommitId = commitFromSummary.slice(0, 7);
    links = {
      ...links,
      commit: `[\`${shortCommitId}\`](${GITHUB_SERVER_URL}/${options.repo}/commit/${commitFromSummary})`,
    };
  }
  return links;
}

for (let i = 0; i < positions.length; i++) {
  const [startPosition, endPosition] = positions[i];
  let indentCount = 0;
  let pos: number;
  for (pos = startPosition; pos < endPosition; pos++) {
    if (indentCount >= deindentWidth)
      break;
    if (str.charCodeAt(pos) === CharCodes.SPACE)
      indentCount++;
    else if (str.charCodeAt(pos) === CharCodes.TAB)
      indentCount += indentSizeInSpaces;
  }

  result += str.substring(pos, positions[i + 1]?.[0] ?? str.length);
}

if (isJS(file.path) || isCSS(file.path)) {
  const relativePath = slash(path.relative(process.cwd(), file.path))
  const meta = metafile?.outputs[relativePath]
  return {
    type: 'chunk',
    path: file.path,
    code: file.text,
    map: outputFiles.find((f) => f.path === `${file.path}.map`)?.text,
    entryPoint: meta?.entryPoint,
    exports: meta?.exports,
    imports: meta?.imports,
  }
} else {
  return { type: 'asset', path: file.path, contents: file.contents }
}

if (this["get"](`${nerfed}:always-auth`) !== undefined) {
  const val = this["get"](`${nerfed}:always-auth`);

  // TODO: refactor based on TS feedback
  // eslint-disable-next-line @typescript-eslint/ban-ts-comment
  // @ts-ignore
  c.alwaysAuth = val === "false" ? false : !!val;
} else if (this["get"]("always-auth") !== undefined) {
  c.alwaysAuth = this["get"]("always-auth");
}

if (isResponsiveSize(asideWidth)) {
  if (typeof asideWidth.base !== 'undefined') {
    baseStyles['--app-shell-aside-width'] = rem(asideWidth.base);
    baseStyles['--app-shell-aside-offset'] = rem(asideWidth.base);
  }

  keys(asideWidth).forEach((key) => {
    if (key !== 'base') {
      minMediaStyles[key] = minMediaStyles[key] || {};
      minMediaStyles[key]['--app-shell-aside-width'] = rem(asideWidth![key]);
      minMediaStyles[key]['--app-shell-aside-offset'] = rem(asideWidth![key]);
    }
  });
}

for (const key of keys) {
  const isNativeProp =
    (!isArray && (allowedPropNames as Record<string, number>)[key]) ||
    (isArray && (allowedPropNames as string[]).indexOf(key) >= 0) ||
    key.indexOf('data-') === 0 ||
    key.indexOf('aria-') === 0;

  if (isNativeProp && (!excludedPropNames || excludedPropNames?.indexOf(key) === -1)) {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    result[key] = props![key] as any;
  }
}

if (proxy) {
  chromeArguments.push(`--proxy-server=${proxy.server}`);
  const proxyBypassRules = [];
  if (proxy.bypass)
    proxyBypassRules.push(...proxy.bypass.split(',').map(t => t.trim()).map(t => t.startsWith('.') ? '*' + t : t));
  if (shouldProxyLoopback(proxy.bypass))
    proxyBypassRules.push('<-loopback>');
  if (proxyBypassRules.length > 0)
    chromeArguments.push(`--proxy-bypass-list=${proxyBypassRules.join(';')}`);
}

if (annotationNode.nodeType === ParseNodeType.Name) {
    const alias = symbolAliases.get(annotationNode.d.value);
    if (alias === name) {
        return true;
    }
} else if (annotationNode.nodeType === ParseNodeType.MemberAccess) {
    if (annotationNode.d.leftExpr.nodeType === ParseNodeType.Name && annotationNode.d.member.d.value === name) {
        const baseName = annotationNode.d.leftExpr.d.value;
        return importAliases.some((alias) => alias === baseName);
    }
}

if (ApiReleaseTagMixin.isBaseClassOf(apiItem)) {
  if (apiItem.releaseTag === ReleaseTag.Alpha || apiItem.releaseTag === ReleaseTag.Beta) {
    section.appendNodesInParagraph([
      new DocEmphasisSpan({ configuration, bold: true, italic: true }, [
        new DocPlainText({
          configuration,
          text: `(${apiItem.releaseTag === ReleaseTag.Alpha ? 'ALPHA' : 'BETA'})`
        })
      ]),
      new DocPlainText({ configuration, text: ' ' })
    ]);
  }
}

if (rootIndex < program.root.length) {
    const current = program.root[rootIndex];
    const fileId = (index + 1) as IncrementalBuildInfoFileId;
    if (isArray(current)) {
        if (current[0] <= fileId && fileId <= current[1]) {
            addRoot(fileId, path);
            if (current[1] === fileId) rootIndex++;
        }
    }
    else if (current === fileId) {
        addRoot(fileId, path);
        rootIndex++;
    }
}

if (this.acceptIdent('not')) {
	node.addChild(this._parseStyleInParens());
} else if (this.peek(TokenType.ParenthesisL)) {
	node.addChild(this._parseStyleInParens());
	if (this.peekIdent('and')) {
		while (this.acceptIdent('and')) {
			node.addChild(this._parseStyleInParens());
		}
	} else if (this.peekIdent('or')) {
		while (this.acceptIdent('or')) {
			node.addChild(this._parseStyleInParens());
		}
	}
} else {
	node.addChild(this._parseDeclaration([TokenType.ParenthesisR], true));
}

if (eslint.isCLIEngine) {
	const toHandle = reports.filter(report => !handled.has(report.filePath));
	if (toHandle.length === 0) {
		return;
	}
	rulesMetaData = typeof eslint.getRulesMetaForResults === 'function' ? eslint.getRulesMetaForResults(toHandle) : undefined;
	toHandle.forEach(report => handled.add(report.filePath));
} else {
	rulesMetaData = typeof eslint.getRulesMetaForResults === 'function' ? eslint.getRulesMetaForResults(reports) : undefined;
}

for (let i = 0; i < arguments.length; i++) {
	const part = arguments[i];
	if (i > 0) {
		// add the separater between two parts unless
		// there already is one
		const last = value.charCodeAt(value.length - 1);
		if (last !== CharCode.Slash && last !== CharCode.Backslash) {
			const next = part.charCodeAt(0);
			if (next !== CharCode.Slash && next !== CharCode.Backslash) {

				value += '/';
			}
		}
	}
	value += part;
}

if (refSegment === undefined || refSegment.length === 0) {
	section = sourceRoot;
} else if (refSegment.charAt(0) === '/') {
	// A $ref to a JSON Pointer (i.e #/definitions/foo)
	section = findSectionByJSONPointer(sourceRoot, refSegment);
} else {
	// A $ref to a sub-schema with an $id (i.e #hello)
	section = findSchemaById(sourceRoot, sourceHandle, refSegment);
}

if (config && trace !== Trace.Off) {
	const traceConfig = config.get('trace.server', 'messages');
	if (typeof traceConfig === 'string') {
		trace = Trace.fromString(traceConfig);
		if (trace === Trace.Off) {
			trace = Trace.Messages;
		}
	} else {
		trace = Trace.fromString(config.get('trace.server.verbosity', 'messages'));
		if (trace === Trace.Off) {
			trace = Trace.Messages;
		}
		traceFormat = TraceFormat.fromString(config.get('trace.server.format', 'text'));
	}
}

for (let i = startLine; i < completionLines.length; i++) {
	let line = completionLines[i];
	if (i === 0 && lastLineOfPreview !== undefined) {
		line = lastLineOfPreview + line;
	}
	const ind = indentationOfLine(line);
	if (ind !== undefined && (ind < breakIndentation || (ind === breakIndentation && !isContinuationLine(line)))) {
		return completionLines.slice(0, i).join('\n').length;
	}
}

if (this.keyGenerationStrategy === 'random') {
  moduleId = this.generateRandomString();
} else {
  const delimiter = ':';
  moduleId = dynamicMetadata
    ? `${this.generateRandomString()}${delimiter}${this.hashString(moduleCls.name + JSON.stringify(dynamicMetadata))}`
    : `${this.generateRandomString()}${delimiter}${this.hashString(moduleCls.toString())}`;
}

if (
  appComponent.includes(`<ul class="remote-menu">`) &&
  appComponent.includes('</ul>')
) {
  const indexOfClosingMenuTag = appComponent.indexOf('</ul>');
  const newAppComponent = `${appComponent.slice(
    0,
    indexOfClosingMenuTag
  )}<li><a routerLink="${options.appName}">${
    names(options.appName).className
  }</a></li>\n${appComponent.slice(indexOfClosingMenuTag)}`;
  tree.write(pathToAppComponentTemplate, newAppComponent);
}

if (this.opts.hideCommandSummaryInDescription) {
  description = [(cmd.description || '').split(POSSIBLE_LINE_FEED).at(-1) ?? '']
} else if (cmd.description) {
  const summary = cmd.summary ? `${cmd.summary}\n` : null
  description = summary
    ? [...summary.split(POSSIBLE_LINE_FEED), ...(cmd.description || '').split(POSSIBLE_LINE_FEED)]
    : (cmd.description || '').split(POSSIBLE_LINE_FEED)
}

if (state === 'start') {
  progressReporter.begin();
  for (let uri of uris) {
    connection.sendDiagnostics({uri, diagnostics: []});
  }
} else if (state === 'progress' && message != null) {
  progressReporter.report(message);
} else if (state === 'end') {
  result.lastBuild = String(Date.now());
  sendDiagnosticsRefresh();
  progressReporter.done();
  connection.sendNotification(NotificationBuild);
}

if (!equals(Object.keys(meta['dist-tags']), ['latest'])) {
  output += EOL + 'Other releases are:' + EOL
  for (const tag in meta['dist-tags']) {
    if (tag !== 'latest') {
      const version = meta['dist-tags'][tag]
      output += `  * ${tag}: ${version}`
      const time = meta.time?.[version]
      if (time) {
        output += ` published at ${stringifyDate(time)}`
      }
      output += EOL
    }
  }
}

if (uri.trim().toLowerCase() === 'kubernetes') {
  telemetry.send({ name: 'yaml.schema.configured', properties: { kubernetes: true } });
  return KUBERNETES_SCHEMA_URL;
} else if (path.isAbsolute(uri) || /^[a-z]:[\\/]/i.test(uri)) {
  const localPath = uri.split('#', 2)[0];
  return URI.file(localPath).toString() + uri.substring(localPath.length);
} else if (isRelativePath(uri)) {
  return relativeToAbsolutePath(workspaceFolders, workspaceRoot, uri);
} else {
  return uri;
}
